            position: relative;
            z-index: 2; /* 确保在粒子上 */
        }
        /* 顶部装饰线 */
        .meow-footer::before {
            content: '';
            display: block;
            width: 70%;
            height: 1px;
            margin: 0 auto 15px;
            background: var(--footer-border);
        }

        .footer-deco { 
            color: var(--accent); 
            opacity: 0.6; 
            font-size: 0.85rem; 
            margin-bottom: 8px;
            display: block; 
        }

        .footer-text { 
            margin: 0 0 15px 0; 
            font-size: 1.1em; 
            font-family: cursive, serif;
            color: var(--accent); 
        }

        .meow-footer span {
            color: var(--accent);
        }

        /* --- 新款胶囊样式工具栏 --- */
        .theme-capsule {
            display: inline-flex;
            align-items: center;
            justify-content: center;
            border: 1px solid var(--border-color);
            border-radius: 50px;
            padding: 4px;
            gap: 4px;
            background: rgba(0, 0, 0, 0.05);
            transition: all 0.3s;
        }

        body.theme-dark .theme-capsule {
            background: rgba(255, 255, 255, 0.02);
        }

        .theme-capsule:hover {
            border-color: var(--accent);
        }

        /* 按钮单体 */
        .capsule-btn {
            cursor: pointer;
            font-size: 1rem;
            color: var(--text-sub);
            width: 36px;
            height: 32px;
            display: flex;
            align-items: center;
            justify-content: center;
            border-radius: 20px;
            transition: all 0.25s cubic-bezier(0.4, 0, 0.2, 1);
        }

        .capsule-btn:hover {
            color: var(--accent);
            background: rgba(128, 128, 128, 0.08);
        }

        /* 激活状态 */
        .capsule-btn.active {
            color: var(--accent);
            text-shadow: 0 0 10px var(--accent-bg);
            transform: scale(1.05);
        }

        /* 分割线 */
        .capsule-divider {
            width: 1px;
            height: 14px;
            background-color: var(--border-color);
            opacity: 0.6;
        }

    </style>
</head>
