async function showPanel(showPresetsFirst = false) {
    if ($('#control-panel-container').length > 0) {
        $('#control-panel-container').addClass('visible');
        if (showPresetsFirst) {
            setTimeout(() => {
                $('#control-panel-container').find('button[data-panel="presets"]').trigger('click');
            }, 50);
        }
        return;
    }
    loadSettings();
    if (!$('link[href*="fontawesome"]').length) {
        faLink = $('<link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/5.15.4/css/all.min.css">');
        $('head').append(faLink);
    }
    styleTag = $('<style>').attr('id', 'control-panel-style').html(panelCss).appendTo('head');
    panel = $(panelHtml);
    $('body').append(panel);
    stagedPrompts = null;
    if (settings.autoTheme) {
        const hour = new Date().getHours();
        settings.theme = hour >= 6 && hour < 18 ? 'light' : 'dark';
    }
    setPanelTheme(settings.theme);
    updateThemeToggleButton();
    await renderStatusDisplay();
    await renderPresetPanel();
    await renderCommandPanel();
    bindPanelEvents();
    setTimeout(() => {
        panel.addClass('visible');
        const $controlPanel = panel.find('.control-panel');
        // 只有在没有 top/left 的情况下才计算初始居中位置
        if (!$controlPanel.attr('style') || ($controlPanel.css('top') === '0px' && $controlPanel.css('left') === '0px')) {
            const viewW = window.parent.innerWidth;
            const viewH = window.parent.innerHeight;
            const panelW = $controlPanel.outerWidth() ?? 0;
            const panelH = $controlPanel.outerHeight() ?? 0;
            const initialX = Math.max(20, (viewW - panelW) / 2);
            const initialY = Math.max(20, (viewH - panelH) / 2);
            $controlPanel.css({ top: `${initialY}px`, left: `${initialX}px` });
        }
        if (showPresetsFirst) {
            panel.find('button[data-panel="presets"]').trigger('click');
        }
    }, 50);
}
function hidePanel() {
    if (panel) {
        panel.removeClass('visible');
        setTimeout(() => {
            panel?.remove();
            panel = null;
            styleTag?.remove();
            styleTag = null;
        }, 300);
    }
}
function setPanelTheme(theme) {
    const isDark = theme === 'dark';
    if (!panel)
        return;
    panel.find('.control-panel').toggleClass('dark-mode', isDark);
    panel.find('#theme-toggle-button i').attr('class', isDark ? 'fas fa-sun' : 'fas fa-moon');
    settings.theme = theme;
}
async function toggleTheme() {
    if (!panel)
        return;
    const isCurrentlyDark = panel.find('.control-panel').hasClass('dark-mode');
    setPanelTheme(isCurrentlyDark ? 'light' : 'dark');
    settings.autoTheme = false;
    const toSave = { ...settings, initialized: true };
    replaceVariables(toSave, { type: 'script', script_id: SCRIPT_ID });
    updateThemeToggleButton();
}
function updateThemeToggleButton() {
    if (!panel)
        return;
    const button = panel.find('button[data-action="toggle_auto_theme"]');
    button.html(`<i class="fas fa-palette fa-fw"></i> 自动主题: ${settings.autoTheme ? '开' : '关'}`);
