function resolveButtonApi() {
    const parentWin = window.parent && window.parent !== window ? window.parent : window;
    const helper = window.TavernHelper ?? parentWin.TavernHelper;
    const contexts = [
        { source: window, bind: window },
        { source: parentWin, bind: parentWin },
        { source: helper, bind: helper },
        { source: helper?.scriptButtons, bind: helper?.scriptButtons },
    ].filter(entry => entry.source);
    const pick = (name) => {
        for (const { source, bind } of contexts) {
            const fn = source && source[name];
            if (typeof fn === 'function') {
                return fn.bind(bind);
            }
        }
        return null;
    };
    const appendButtons = pick('appendInexistentScriptButtons') ?? pick('replaceScriptButtons');
    return {
        appendButtons,
        getButtonEvent: pick('getButtonEvent'),
        eventOn: pick('eventOn'),
